return ['project-id-version'=>'PN Customers Manager','report-msgid-bugs-to'=>'','pot-creation-date'=>'2024-07-31 14:12+0000','po-revision-date'=>'2026-04-10 12:31+0000','last-translator'=>'','language-team'=>'Español','language'=>'es_ES','plural-forms'=>'nplurals=2; plural=n != 1;','mime-version'=>'1.0','content-type'=>'text/plain; charset=UTF-8','content-transfer-encoding'=>'8bit','x-generator'=>'Loco https://localise.biz/','x-loco-version'=>'2.8.3; wp-6.9.4; php-8.3.30','x-domain'=>'crmpn','messages'=>['%1$s has invited you to join %2$s. Click the button below to accept the invitation and set up your account.'=>'%1$s te ha invitado a unirte a %2$s. Haz clic en el botón de abajo para aceptar la invitación y configurar tu cuenta.','%d user(s) assigned the role successfully.'=>'%d usuarios han asignado el rol correctamente.','%d user(s) removed from the role successfully.'=>'%d usuarios eliminados del rol correctamente.','%s has invited you!'=>'¡%s te ha invitado!','%s is required.'=>'Se requiere %s.','%s slug'=>'Slug de %s','%s te ha invitado!'=>'%s te ha invitado!','-- Seleccionar frase --'=>'-- Seleccionar frase --','-- Select funnel --'=>'-- Seleccionar embudo --','-- Select page --'=>'-- Seleccionar página --','-- Select template --'=>'-- Seleccionar plantilla --','-- Use global --'=>'-- Usar global --','0 = cold lead, 100 = hot lead.'=>'0 = cable frío, 100 = cable caliente.','1 - 10 people'=>'1 - 10 personas','1 year'=>'1 año','11 - 50 people'=>'11 - 50 personas','201 - 500 people'=>'201 - 500 personas','24 h'=>'24 horas','30 days'=>'30 días','51 - 200 people'=>'51 - 200 personas','7 days'=>'7 días','<strong>How to configure it:</strong><br>1. Create any secret string (e.g.: <code>my_ig_token_2024</code>) and type it here.<br>2. Save the settings.<br>3. When configuring the webhook on Meta, use exactly the same string as the &laquo;Verify Token&raquo;.'=>'<strong>Cómo configurarlo:</strong><br> 1. Crea cualquier cadena secreta (por ejemplo: <code>my_ig_token_2024</code> ) e introdúcela aquí.<br> 2. Guarda la configuración.<br> 3. Al configurar el webhook en Meta, utilice exactamente la misma cadena que en el «Token de verificación».','<strong>How to configure it:</strong><br>1. Create any secret string (e.g.: <code>my_secure_token_2024</code>) and type it here.<br>2. Save the settings.<br>3. When configuring the webhook on Meta (below), you will be asked for a &laquo;Verify Token&raquo;: use exactly the same string.<br>Meta will send a GET request with this token to verify that the webhook is yours.'=>'<strong>Cómo configurarlo:</strong><br> 1. Crea cualquier cadena secreta (por ejemplo: <code>my_secure_token_2024</code> ) e introdúcela aquí.<br> 2. Guarda la configuración.<br> 3. Al configurar el webhook en Meta (a continuación), se le pedirá un «Token de verificación»: utilice exactamente la misma cadena.<br> Meta enviará una solicitud GET con este token para verificar que el webhook le pertenece.','<strong>How to configure the webhook on Meta:</strong><br>1. Copy the URL shown above.<br>2. Go to <a href="https://developers.facebook.com/apps/" target="_blank">Meta for Developers</a> &gt; your app &gt; Instagram &gt; Webhooks.<br>3. Paste the URL in the &laquo;Callback URL&raquo; field.<br>4. In &laquo;Verify Token&raquo; type the same token you configured above.<br>5. Click &laquo;Verify and Save&raquo;.<br>6. Subscribe to the <code>messages</code> webhook field.'=>'<strong>Cómo configurar el webhook en Meta:</strong><br> 1. Copie la URL que se muestra arriba.<br> 2. Ve a <a href="https://developers.facebook.com/apps/" target="_blank">Meta para desarrolladores</a> &gt; tu aplicación &gt; Instagram &gt; Webhooks.<br> 3. Pegue la URL en el campo «URL de devolución de llamada».<br> 4. En «Verificar token», escriba el mismo token que configuró anteriormente.<br> 5. Haga clic en «Verificar y guardar».<br> 6. Suscríbase al campo webhook <code>messages</code> .','<strong>How to configure the webhook on Meta:</strong><br>1. Copy the URL shown above.<br>2. Go to <a href="https://developers.facebook.com/apps/" target="_blank">Meta for Developers</a> &gt; your app &gt; WhatsApp &gt; Configuration.<br>3. In the &laquo;Webhook&raquo; section, click &laquo;Edit&raquo;.<br>4. Paste the URL in the &laquo;Callback URL&raquo; field.<br>5. In &laquo;Verify Token&raquo; type the same token you configured above.<br>6. Click &laquo;Verify and Save&raquo;.<br>7. In &laquo;Webhook fields&raquo;, subscribe to the <code>messages</code> field.'=>'<strong>Cómo configurar el webhook en Meta:</strong><br> 1. Copie la URL que se muestra arriba.<br> 2. Ve a <a href="https://developers.facebook.com/apps/" target="_blank">Meta para desarrolladores</a> &gt; tu aplicación &gt; WhatsApp &gt; Configuración.<br> 3. En la sección «Webhook», haga clic en «Editar».<br> 4. Pegue la URL en el campo «URL de devolución de llamada».<br> 5. En «Verificar token», escriba el mismo token que configuró anteriormente.<br> 6. Haga clic en «Verificar y guardar».<br> 7. En «Campos de webhook», suscríbase al campo <code>messages</code> .','<strong>How to get it (temporary token):</strong><br>1. Go to <a href="https://developers.facebook.com/apps/" target="_blank">Meta for Developers</a> &gt; your app &gt; WhatsApp &gt; API Setup.<br>2. In the &laquo;Temporary access token&raquo; section, click <strong>Generate</strong> and copy the token. <em>Expires in ~24 hours.</em><br><br><strong>Permanent token (recommended for production):</strong><br>1. Go to <a href="https://business.facebook.com/settings/" target="_blank">Meta Business Suite</a> &gt; Settings &gt; Business settings.<br>2. Under <strong>Users &gt; System Users</strong>, create a System User of type <em>Admin</em>.<br>3. Assign the WhatsApp App asset to it.<br>4. Generate a token with the <code>whatsapp_business_messaging</code> permission.<br>5. This token does not expire and does not need renewal.'=>'<strong>Cómo obtenerlo (token temporal):</strong><br> 1. Ve a <a href="https://developers.facebook.com/apps/" target="_blank">Meta para desarrolladores</a> &gt; tu aplicación &gt; WhatsApp &gt; Configuración de API.<br> 2. En la sección «Token de acceso temporal», haga clic en <strong>Generar</strong> y copie el token. <em>Caduca en aproximadamente 24 horas.</em><br><br> <strong>Token permanente (recomendado para producción):</strong><br> 1. Vaya a <a href="https://business.facebook.com/settings/" target="_blank">Meta Business Suite</a> &gt; Configuración &gt; Configuración empresarial.<br> 2. En <strong>Usuarios &gt; Usuarios del sistema</strong> , cree un Usuario del sistema de tipo <em>Administrador</em> .<br> 3. Asígnale el recurso de la aplicación WhatsApp.<br> 4. Genera un token con el permiso <code>whatsapp_business_messaging</code> .<br> 5. Este token no caduca y no necesita renovación.','<strong>How to get it:</strong><br>1. Go to <a href="https://developers.facebook.com/apps/" target="_blank">Meta for Developers</a> &gt; your app &gt; Instagram &gt; API Setup.<br>2. Copy the Instagram-scoped Page ID (numeric ID) and paste it here.'=>'<strong>Cómo conseguirlo:</strong><br> 1. Ve a <a href="https://developers.facebook.com/apps/" target="_blank">Meta para desarrolladores</a> &gt; tu aplicación &gt; Instagram &gt; Configuración de API.<br> 2. Copie el ID de página de Instagram (ID numérico) y péguelo aquí.','<strong>How to get it:</strong><br>1. Go to <a href="https://developers.facebook.com/apps/" target="_blank">Meta for Developers</a> &gt; your app &gt; Instagram &gt; API Setup.<br>2. Generate an access token with <code>instagram_manage_messages</code> permission.<br><br><strong>Permanent token (recommended):</strong><br>Use a System User token from <a href="https://business.facebook.com/settings/" target="_blank">Meta Business Suite</a> with <code>instagram_manage_messages</code> permission.'=>'<strong>Cómo conseguirlo:</strong><br> 1. Ve a <a href="https://developers.facebook.com/apps/" target="_blank">Meta para desarrolladores</a> &gt; tu aplicación &gt; Instagram &gt; Configuración de API.<br> 2. Genera un token de acceso con el permiso <code>instagram_manage_messages</code> .<br><br> <strong>Ficha permanente (recomendada):</strong><br> Utilice un token de usuario del sistema de <a href="https://business.facebook.com/settings/" target="_blank">Meta Business Suite</a> con el permiso <code>instagram_manage_messages</code> .','<strong>How to get it:</strong><br>1. Go to <a href="https://developers.facebook.com/apps/" target="_blank">Meta for Developers</a> &gt; your app &gt; WhatsApp &gt; API Setup.<br>2. In the &laquo;From&raquo; section your phone number appears with its <strong>Phone number ID</strong> below.<br>3. Copy the numeric ID (e.g.: <code>123456789012345</code>) and paste it here.'=>'<strong>Cómo conseguirlo:</strong><br> 1. Ve a <a href="https://developers.facebook.com/apps/" target="_blank">Meta para desarrolladores</a> &gt; tu aplicación &gt; WhatsApp &gt; Configuración de API.<br> 2. En la sección «De» aparece tu número de teléfono con su <strong>ID de número de teléfono</strong> debajo.<br> 3. Copie el ID numérico (por ejemplo: <code>123456789012345</code> ) y péguelo aquí.','<strong>How to get it:</strong><br>1. Go to <a href="https://platform.openai.com/api-keys" target="_blank">platform.openai.com/api-keys</a>.<br>2. Click &laquo;Create new secret key&raquo;.<br>3. Copy the generated key (starts with <code>sk-</code>) and paste it here.<br><strong>Important:</strong> The key is only shown once when created. If you lose it, you will need to generate a new one.'=>'<strong>Cómo conseguirlo:</strong><br> 1. Vaya a <a href="https://platform.openai.com/api-keys" target="_blank">platform.openai.com/api-keys</a> .<br> 2. Haga clic en «Crear nueva clave secreta».<br> 3. Copie la clave generada (que comienza con <code>sk-</code> ) y péguela aquí.<br> <strong>Importante:</strong> La clave solo se muestra una vez al crearla. Si la pierde, deberá generar una nueva.','[%1$s] New order via %2$s'=>'[%1$s] Nuevo pedido a través de %2$s','A Page Access Token with <code>pages_read_engagement</code> and <code>read_insights</code> permissions.'=>'Un token de acceso a la página con permisos <code>pages_read_engagement</code> y <code>read_insights</code>.','Accept Invitation'=>'Aceptar invitación','Accept orders via chat'=>'Acepta pedidos a través del chat.','Access Denied'=>'Acceso denegado','Access restricted'=>'Acceso restringido','Access the CRM'=>'Acceda al CRM','Acciones'=>'Acciones','Account health'=>'Estado de la cuenta','Acercar'=>'Acercar','Action not allowed.'=>'Acción no permitida.','Actions'=>'Acciones','Active'=>'Activa','Actual'=>'Actual','Actual vs Projected'=>'Real vs. Proyectado','Add audio'=>'Agregar audio','Add audios'=>'Agregar audios','Add contact'=>'Añadir contacto','Add element'=>'Añadir elemento','Add file'=>'Agregar archivo','Add files'=>'Agregar archivos','Add image'=>'Añadir imagen','Add images'=>'Añadir imágenes','Add new Funnel'=>'Agregar nuevo embudo','Add New Funnel category'=>'Agregar nueva categoría de embudo','Add new Organization'=>'Agregar nueva organización','Add rel=nofollow'=>'Agregar rel=nofollow','Add video'=>'Agregar vídeo','Add videos'=>'Agregar vídeos','Additional information the AI will use as reference to respond.'=>'Información adicional que la IA utilizará como referencia para responder.','Additional shipping information'=>'Información adicional sobre el envío','Address'=>'DIRECCIÓN','Adds all variations with their attributes, prices and direct purchase links. Warning: this can significantly increase AI API call costs.'=>'Agrega todas las variantes con sus atributos, precios y enlaces de compra directa. Advertencia: esto puede aumentar significativamente los costos de las llamadas a la API de IA.','Advanced CRM fields'=>'Campos de CRM avanzados','AI Model'=>'Modelo IA','Alejar'=>'Alejar','Alguien'=>'Alguien','Alignment'=>'Alineación','All'=>'Todos','All Funnel categories'=>'Todas las categorías de embudos','A